import React, { useState, useEffect } from "react";
import "./Placement.css";

export default function Placement() {
  const [placements, setPlacements] = useState([]);
  const currentUser = JSON.parse(localStorage.getItem("loggedInUser"));
  const role = currentUser?.role || "student";

  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("placements")) || [];
    setPlacements(stored);
  }, []);

  const handleAdd = () => {
    const title = prompt("Enter Placement Role:");
    const company = prompt("Enter Company Name:");
    const description = prompt("Enter Description:");
    const newItem = {
      id: Date.now(),
      title,
      company,
      description,
    };
    const updated = [...placements, newItem];
    setPlacements(updated);
    localStorage.setItem("placements", JSON.stringify(updated));
  };

  const handleEdit = (id) => {
    const title = prompt("Edit Title:");
    const company = prompt("Edit Company:");
    const description = prompt("Edit Description:");
    const updated = placements.map((item) =>
      item.id === id ? { ...item, title, company, description } : item
    );
    setPlacements(updated);
    localStorage.setItem("placements", JSON.stringify(updated));
  };

  const handleDelete = (id) => {
    const updated = placements.filter((item) => item.id !== id);
    setPlacements(updated);
    localStorage.setItem("placements", JSON.stringify(updated));
  };

  const handleApply = (id) => {
    alert(`Applied to placement ID: ${id}`);
  };

  return (
    <div className="page-container">
      <h2 className="page-title">Placement Opportunities</h2>
      {role === "admin" || role === "hr" ? (
        <button className="add-btn" onClick={handleAdd}>Add Placement</button>
      ) : null}

      <div className="cards-grid">
        {placements.length === 0 ? (
          <p>No placements available.</p>
        ) : (
          placements.map((item) => (
            <div className="card" key={item.id}>
              <h3>{item.title}</h3>
              <p><strong>Company:</strong> {item.company}</p>
              <p>{item.description}</p>

              {role === "student" && (
                <div className="card-actions">
                  <button onClick={() => handleApply(item.id)}>Apply</button>
                </div>
              )}

              {(role === "admin" || role === "hr") && (
                <div className="card-actions">
                  <button onClick={() => handleEdit(item.id)}>Edit</button>
                  {role === "admin" && (
                    <button onClick={() => handleDelete(item.id)}>Delete</button>
                  )}
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
